              {form.password && (
                <div>
                  <label className="label">New Password</label>
                  <input type="password" value={form.newPassword} onChange={e => setForm(f => ({...f, newPassword: e.target.value}))}
                    className="input-field max-w-sm" placeholder="Min 6 characters" required={!!form.password} minLength="6" />
                </div>
              )}
            </div>
          </div>

          <div className="pt-4">
            <button type="submit" disabled={saving} className="btn-primary py-2.5 px-6 disabled:opacity-60 flex items-center gap-2">
              {saving ? <Loader2 size={16} className="animate-spin" /> : <Settings size={16} />} 
              Save Changes
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useState, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDropzone } from 'react-dropzone';
import { Upload, CheckCircle, Copy, X, Loader2, AlertTriangle, Lock } from 'lucide-react';
import toast from 'react-hot-toast';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const TALUKAS = ['Pune', 'Haveli', 'Khed', 'Baramati', 'Junnar', 'Shirur', 'Indapur', 'Daund', 'Mawal', 'Ambegaon', 'Purandhar', 'Bhor', 'Mulshi', 'Velhe'];
const DEPARTMENTS = ['Road','Water','Electricity','Revenue','Police','Health','Education','Agriculture','Other'];

export default function ComplaintForm() {
  const { t, lang } = useLang();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ name:'', mobile: user?.mobile || '', village:'', taluka:'', department:'', description:'' });
  const mobileReadOnly = !!(user?.role === 'citizen' && user?.mobile);
  const [photo, setPhoto] = useState(null);
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(null);

  const onDrop = useCallback(files => {
    if (files[0]) setPhoto(files[0]);
  }, []);
  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop, accept: { 'image/*': [], 'application/pdf': ['.pdf'] }, maxSize: 15 * 1024 * 1024, maxFiles: 1
  });

  // Revoke object URL to prevent memory leaks
  useEffect(() => {
    if (!photo) return;
    const url = URL.createObjectURL(photo);
    return () => URL.revokeObjectURL(url);
  }, [photo]);

  const validate = () => {
    const errs = {};
    if (!form.name.trim()) errs.name = t.required;
    if (!form.mobile.match(/^[6-9]\d{9}$/)) errs.mobile = 'Enter valid 10-digit mobile number';
    if (!form.village.trim()) errs.village = t.required;
    if (!form.taluka) errs.taluka = t.required;
    if (!form.department) errs.department = t.required;
    if (!form.description.trim()) errs.description = 'Description is required';
    else if (form.description.length > 500) errs.description = 'Description cannot exceed 500 characters';
    return errs;
  };

  const handleChange = e => {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
    if (errors[name]) setErrors(er => ({ ...er, [name]: null }));
  };

  const handleSubmit = async e => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);

    const data = new FormData();
    Object.entries(form).forEach(([k, v]) => data.append(k, v));
    if (photo) data.append('photo', photo);

    try {
      const res = await api.post('/complaints', data);
      setSuccess(res.data);
      toast.success(t.successSubmit);
    } catch (err) {
      const msg = err.response?.data?.message || 'Submission failed. Please try again.';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  const copyId = () => {
    navigator.clipboard.writeText(success.complaintId);
    toast.success('Complaint ID copied!');
  };

  if (success) {
    return (
      <div className="max-w-2xl mx-auto px-4 py-16 animate-slide-up">
        <div className="card text-center border-2 border-green-200 dark:border-green-800">
          <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mx-auto mb-4">
            <CheckCircle size={36} className="text-green-600" />
          </div>
          <h2 className="text-2xl font-extrabold text-gray-900 dark:text-white mb-1">{t.successSubmit}</h2>
          <p className="font-marathi text-green-700 dark:text-green-400 mb-6">αñåαñ¬αñ▓αÑÇ αññαñòαÑìαñ░αñ╛αñ░ αñ»αñ╢αñ╕αÑìαñ╡αÑÇαñ░αñ┐αññαÑìαñ»αñ╛ αñ¿αÑïαñéαñªαñ╡αñ▓αÑÇ αñùαÑçαñ▓αÑÇ.</p>

          <div className="bg-saffron-50 dark:bg-saffron-900/20 border border-saffron-200 dark:border-saffron-700 rounded-xl p-5 mb-6">
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-1">{t.complaintId}</p>
